  890: /* Wait for a transaction commit to reach at least the given state. */
  891: static noinline void wait_for_commit(struct btrfs_transaction *commit,
  892: 				     const enum btrfs_trans_state min_state)
  893: {
  894: 	struct btrfs_fs_info *fs_info = commit->fs_info;
  895: 	u64 transid = commit->transid;
  896: 	bool put = false;
  897: 
  898: 	/*
  899: 	 * At the moment this function is called with min_state either being
  900: 	 * TRANS_STATE_COMPLETED or TRANS_STATE_SUPER_COMMITTED.
  901: 	 */
  902: 	if (min_state == TRANS_STATE_COMPLETED)
  903: 		btrfs_might_wait_for_state(fs_info, BTRFS_LOCKDEP_TRANS_COMPLETED);
  904: 	else
  905: 		btrfs_might_wait_for_state(fs_info, BTRFS_LOCKDEP_TRANS_SUPER_COMMITTED);
  906: 
  907: 	while (1) {
  908: 		wait_event(commit->commit_wait, commit->state >= min_state);
  909: 		if (put)
  910: 			btrfs_put_transaction(commit);
  911: 
  912: 		if (min_state < TRANS_STATE_COMPLETED)
  913: 			break;
  914: 
  915: 		/*
  916: 		 * A transaction isn't really completed until all of the
  917: 		 * previous transactions are completed, but with fsync we can
  918: 		 * end up with SUPER_COMMITTED transactions before a COMPLETED
  919: 		 * transaction. Wait for those.
  920: 		 */
  921: 
  922: 		spin_lock(&fs_info->trans_lock);
  923: 		commit = list_first_entry_or_null(&fs_info->trans_list,
  924: 						  struct btrfs_transaction,
  925: 						  list);
  926: 		if (!commit || commit->transid > transid) {
  927: 			spin_unlock(&fs_info->trans_lock);
  928: 			break;
  929: 		}
  930: 		refcount_inc(&commit->use_count);
  931: 		put = true;
  932: 		spin_unlock(&fs_info->trans_lock);
  933: 	}
  934: }
