 1199: int btrfs_resume_dev_replace_async(struct btrfs_fs_info *fs_info)
 1200: {
 1201: 	struct task_struct *task;
 1202: 	struct btrfs_dev_replace *dev_replace = &fs_info->dev_replace;
 1203: 
 1204: 	down_write(&dev_replace->rwsem);
 1205: 
 1206: 	switch (dev_replace->replace_state) {
 1207: 	case BTRFS_IOCTL_DEV_REPLACE_STATE_NEVER_STARTED:
 1208: 	case BTRFS_IOCTL_DEV_REPLACE_STATE_FINISHED:
 1209: 	case BTRFS_IOCTL_DEV_REPLACE_STATE_CANCELED:
 1210: 		up_write(&dev_replace->rwsem);
 1211: 		return 0;
 1212: 	case BTRFS_IOCTL_DEV_REPLACE_STATE_STARTED:
 1213: 		break;
 1214: 	case BTRFS_IOCTL_DEV_REPLACE_STATE_SUSPENDED:
 1215: 		dev_replace->replace_state =
 1216: 			BTRFS_IOCTL_DEV_REPLACE_STATE_STARTED;
 1217: 		break;
 1218: 	}
 1219: 	if (!dev_replace->tgtdev || !dev_replace->tgtdev->bdev) {
 1220: 		btrfs_info(fs_info,
 1221: 			   "cannot continue dev_replace, tgtdev is missing");
